1	package clusterpodplacementconfig
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7	
8		"github.com/go-logr/logr"
9		multiarchv1beta1 "github.com/openshift/multiarch-tuning-operator/api/v1beta1"
10		"github.com/openshift/multiarch-tuning-operator/pkg/informers/clusterpodplacementconfig/internal"
11		"k8s.io/client-go/tools/cache"
12		"sigs.k8s.io/controller-runtime/pkg/log"
13		"sigs.k8s.io/controller-runtime/pkg/manager"
14	)
15	
16	// CPPCSyncer syncs ClusterPodPlacementConfig resources using an informer.
17	type CPPCSyncer struct {
18		mgr manager.Manager
19		log logr.Logger
20	}
21	
22	// NewCPPCSyncer creates a new CPPCSyncer.
23	func NewCPPCSyncer(mgr manager.Manager) *CPPCSyncer {
24		return &CPPCSyncer{
25			mgr: mgr,
26		}
27	}
28	
29	// Start initializes the CPPC informer and starts syncing.
30	func (s *CPPCSyncer) Start(ctx context.Context) error {
31		s.log = log.FromContext(ctx, "handler", "CPPCSyncer")
32		s.log.Info("Starting CPPC Syncer")
33		mgr := s.mgr
34	
35		// Get informer for ClusterPodPlacementConfig
36		CPPCInformer, err := mgr.GetCache().GetInformerForKind(ctx, multiarchv1beta1.GroupVersion.WithKind(multiarchv1beta1.ClusterPodPlacementConfigKind))
37		if err != nil {
38			s.log.Error(err, "Error getting informer for ClusterPodPlacementConfig")
39			return err
40		}
41	
42		// Register event handlers
43		_, err = CPPCInformer.AddEventHandler(cache.ResourceEventHandlerFuncs{
44			AddFunc:    s.onAdd(),
45			UpdateFunc: s.onUpdate(),
46			DeleteFunc: s.onDelete(),
47		})
48		if err != nil {
49			s.log.Error(err, "Error registering handler for ClusterPodPlacementConfig")
50			return err
51		}
52	
53		return nil
54	}
55	
56	// onAdd handles the addition of a ClusterPodPlacementConfig.
57	func (s *CPPCSyncer) onAdd() func(obj interface{}) {
58		return func(obj interface{}) {
59			CPPC, ok := obj.(*multiarchv1beta1.ClusterPodPlacementConfig)
60			if !ok {
61				s.log.Error(errors.New("unexpected type, expected ClusterPodPlacementConfig"), "unexpected type",
62					"type", fmt.Sprintf("%T", obj))
63				return
64			}
65	
66			internal.StoreClusterPodPlacementConfig(CPPC)
67			s.log.Info("Added ClusterPodPlacementConfig", "CPPC name", CPPC.Name, "namespace", CPPC.Namespace)
68		}
69	}
70	
71	// onDelete handles the deletion of a ClusterPodPlacementConfig.
72	func (s *CPPCSyncer) onDelete() func(obj interface{}) {
73		return func(obj interface{}) {
74	
75			CPPC, ok := obj.(*multiarchv1beta1.ClusterPodPlacementConfig)
76			if !ok {
77				s.log.Error(errors.New("unexpected type, expected ClusterPodPlacementConfig"), "unexpected type",
78					"type", fmt.Sprintf("%T", obj))
79				return
80			}
81	
82			internal.DeleteClusterPodPlacementConfig()
83			s.log.Info("Deleted ClusterPodPlacementConfig", "name", CPPC.Name, "namespace", CPPC.Namespace)
84		}
85	}
86	
87	// onUpdate handles updates to a ClusterPodPlacementConfig.
88	func (s *CPPCSyncer) onUpdate() func(oldObj, newObj interface{}) {
89		return func(oldobj, newobj interface{}) {
90			oldConfig, ok := oldobj.(*multiarchv1beta1.ClusterPodPlacementConfig)
91	
92			if !ok {
93				s.log.Error(errors.New("unexpected type, expected ClusterPodPlacementConfig"), "unexpected type",
94					"type", fmt.Sprintf("%T", oldobj))
95				return
96			}
97	
98			newConfig, ok := newobj.(*multiarchv1beta1.ClusterPodPlacementConfig)
99			if !ok {
100				s.log.Error(errors.New("unexpected type, expected ClusterPodPlacementConfig"), "unexpected type",
101					"type", fmt.Sprintf("%T", newobj))
102				return
103			}
104	
105			if oldConfig.ResourceVersion == newConfig.ResourceVersion {
106				return
107			}
108	
109			s.onAdd()(newobj)
110		}
111	}
112	
113	// GetClusterPodPlacementConfig provides access to the stored config.
114	func GetClusterPodPlacementConfig() *multiarchv1beta1.ClusterPodPlacementConfig {
115		return internal.GetClusterPodPlacementConfig()
116	}
